use fastly::http::{header, Method, StatusCode};
use fastly::{mime, Error, Request, Response};
use std::collections::HashMap;

const MAX_REQUEST_SIZE: u64 = 10 * 1024 * 1024; // 10MB
const ALLOWED_METHODS: &[Method] = &[
    Method::GET,
    Method::POST,
    Method::PUT,
    Method::DELETE,
    Method::HEAD,
    Method::OPTIONS,
    Method::PATCH,
];

struct BackendConfig {
    name: &'static str,
    host_override: Option<&'static str>,
    use_ssl: bool,
    sni_hostname: Option<&'static str>,
    cert_hostname: Option<&'static str>,
    ca_cert: Option<&'static str>,
}

fn get_backend_configs() -> HashMap<&'static str, BackendConfig> {
    let mut configs = HashMap::new();

    configs.insert(
        "api_backend",
        BackendConfig {
            name: "api_backend",
            host_override: Some("api.example.com"),
            use_ssl: true,
            sni_hostname: Some("api.example.com"),
            cert_hostname: Some("api.example.com"),
            ca_cert: None,
        },
    );

    configs.insert(
        "static_backend",
        BackendConfig {
            name: "static_backend",
            host_override: Some("static.example.com"),
            use_ssl: true,
            sni_hostname: Some("static.example.com"),
            cert_hostname: Some("static.example.com"),
            ca_cert: None,
        },
    );

    configs.insert(
        "legacy_backend",
        BackendConfig {
            name: "legacy_backend",
            host_override: Some("legacy.example.com"),
            use_ssl: true,
            sni_hostname: Some("legacy.example.com"),
            cert_hostname: Some("legacy.example.com"),
            ca_cert: None,
        },
    );

    configs
}

fn validate_request(req: &Request) -> Result<(), Response> {
    if !ALLOWED_METHODS.contains(req.get_method()) {
        return Err(Response::from_status(StatusCode::METHOD_NOT_ALLOWED)
            .with_header(header::ALLOW, "GET, POST, PUT, DELETE, HEAD, OPTIONS, PATCH")
            .with_body_text_plain("Method not allowed\n"));
    }

    if let Some(content_length) = req.get_content_length() {
        if content_length > MAX_REQUEST_SIZE {
            return Err(Response::from_status(StatusCode::PAYLOAD_TOO_LARGE)
                .with_body_text_plain("Request body too large\n"));
        }
    }

    let path = req.get_path();
    if path.contains("..") || path.contains("//") {
        return Err(Response::from_status(StatusCode::BAD_REQUEST)
            .with_body_text_plain("Invalid path\n"));
    }

    if let Some(host) = req.get_header_str(header::HOST) {
        if host.len() > 253 || host.contains('\0') || host.contains('\n') || host.contains('\r') {
            return Err(Response::from_status(StatusCode::BAD_REQUEST)
                .with_body_text_plain("Invalid host header\n"));
        }
    }

    Ok(())
}

fn sanitize_headers(req: &mut Request) {
    let sensitive_headers = [
        "x-fastly-client-ip",
        "fastly-client-ip",
        "x-real-ip",
        "authorization",
        "cookie",
        "x-api-key",
    ];

    for header_name in &sensitive_headers {
        if req.contains_header(header_name) {
            req.remove_header(header_name);
        }
    }

    req.set_header("x-forwarded-proto", "https");
    
    if let Some(client_ip) = req.get_client_ip_addr() {
        req.set_header("x-forwarded-for", client_ip.to_string());
    }
}

fn route_request(path: &str) -> Option<&'static str> {
    if path.starts_with("/api/") {
        Some("api_backend")
    } else if path.starts_with("/static/") || path.starts_with("/assets/") {
        Some("static_backend")
    } else if path.starts_with("/legacy/") {
        Some("legacy_backend")
    } else {
        None
    }
}

fn configure_backend_request(
    mut req: Request,
    config: &BackendConfig,
) -> Result<Request, Error> {
    if let Some(host) = config.host_override {
        req.set_header(header::HOST, host);
    }

    req.set_header("x-forwarded-host", req.get_header_str(header::HOST).unwrap_or(""));
    
    sanitize_headers(&mut req);

    req.set_header("user-agent", "Fastly-Compute-Edge/1.0");
    req.set_header("x-edge-request", "true");

    Ok(req)
}

fn send_to_backend(mut req: Request, backend_name: &str) -> Result<Response, Error> {
    let configs = get_backend_configs();
    
    let config = match configs.get(backend_name) {
        Some(cfg) => cfg,
        None => {
            return Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain("Backend not configured\n"));
        }
    };

    req = configure_backend_request(req, config)?;

    match req.send(backend_name) {
        Ok(mut resp) => {
            resp.remove_header("server");
            resp.remove_header("x-powered-by");
            resp.set_header("x-edge-cache", "MISS");
            resp.set_header("x-content-type-options", "nosniff");
            resp.set_header("x-frame-options", "DENY");
            resp.set_header("strict-transport-security", "max-age=31536000; includeSubDomains");
            
            Ok(resp)
        }
        Err(e) => {
            eprintln!("Backend error: {:?}", e);
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain("Backend unavailable\n"))
        }
    }
}

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    if let Err(error_response) = validate_request(&req) {
        return Ok(error_response);
    }

    let path = req.get_path().to_string();

    if req.get_method() == Method::OPTIONS {
        return Ok(Response::from_status(StatusCode::NO_CONTENT)
            .with_header(header::ALLOW, "GET, POST, PUT, DELETE, HEAD, OPTIONS, PATCH")
            .with_header("access-control-allow-methods", "GET, POST, PUT, DELETE, HEAD, OPTIONS, PATCH")
            .with_header("access-control-max-age", "86400"));
    }

    let backend_name = match route_request(&path) {
        Some(name) => name,
        None => {
            return Ok(Response::from_status(StatusCode::NOT_FOUND)
                .with_body_text_plain("Route not found\n"));
        }
    };

    send_to_backend(req, backend_name)
}